column6:
{
  "non_functional_requirements": [
    {
      "id": "NFR1",
      "description": "System powinien zapewniać spójność danych rezerwacji i grafiku w czasie rzeczywistym, aby uniemożliwić jednoczesną rezerwację tego samego terminu przez więcej niż jednego użytkownika."
    },
    {
      "id": "NFR2",
      "description": "System powinien być dostępny dla użytkowników przez co najmniej 99,5% czasu w skali miesiąca, z wyłączeniem planowanych prac serwisowych."
    },
    {
      "id": "NFR3",
      "description": "System powinien odpowiadać na żądanie przeglądania dostępnych terminów w czasie nie dłuższym niż 2 sekundy dla 95% zapytań przy normalnym obciążeniu."
    },
    {
      "id": "NFR4",
      "description": "System powinien zapewniać uwierzytelnianie i autoryzację użytkowników zgodnie z przypisanymi rolami oraz chronić dostęp do danych rezerwacji i grafików."
    },
    {
      "id": "NFR5",
      "description": "System powinien chronić dane osobowe użytkowników i specjalistów zgodnie z obowiązującymi przepisami prawa oraz dobrymi praktykami bezpieczeństwa."
    },
    {
      "id": "NFR6",
      "description": "System powinien rejestrować operacje związane z tworzeniem, zmianą i anulowaniem rezerwacji oraz zmianami w grafikach specjalistów w celu zapewnienia audytowalności."
    },
    {
      "id": "NFR7",
      "description": "Interfejs systemu powinien być czytelny i intuicyjny dla wszystkich ról użytkowników, umożliwiając wykonanie podstawowych operacji bez potrzeby specjalistycznego szkolenia."
    },
    {
      "id": "NFR8",
      "description": "System powinien być skalowalny w sposób umożliwiający obsługę rosnącej liczby użytkowników, specjalistów i rezerwacji bez istotnego pogorszenia wydajności."
    }
  ],
  "user_stories": [
    {
      "id": "US1",
      "description": "Jako użytkownik chcę przeglądać dostępne terminy wizyt u specjalistów, aby wybrać dogodny termin."
    },
    {
      "id": "US2",
      "description": "Jako użytkownik chcę zarezerwować wybrany termin wizyty, aby umówić spotkanie ze specjalistą."
    },
    {
      "id": "US3",
      "description": "Jako użytkownik chcę anulować własną rezerwację, aby móc zrezygnować z wizyty, gdy nie mogę w niej uczestniczyć."
    },
    {
      "id": "US4",
      "description": "Jako specjalista chcę zarządzać swoim grafikiem, aby udostępniać i aktualizować terminy wizyt."
    },
    {
      "id": "US5",
      "description": "Jako specjalista chcę przeglądać swoje zarezerwowane wizyty, aby planować swoją pracę."
    },
    {
      "id": "US6",
      "description": "Jako administrator chcę zarządzać rolami użytkowników, aby kontrolować uprawnienia dostępu w systemie."
    },
    {
      "id": "US7",
      "description": "Jako administrator chcę nadzorować rezerwacje, aby zapewnić poprawne działanie procesu umawiania wizyt."
    },
    {
      "id": "US8",
      "description": "Jako administrator chcę zarządzać kontami użytkowników i specjalistów, aby utrzymywać aktualność i poprawność danych w systemie."
    }
  ]
}

