column6:
{
  "acceptance_criteria": [
    {
      "id": "AC1",
      "given": "Użytkownik jest na ekranie przeglądania terminów wizyt i w systemie istnieją dostępne terminy specjalistów",
      "when": "Użytkownik wyświetla listę terminów",
      "then": "System pokazuje dostępne terminy wraz z informacją o specjaliście, dacie i godzinie wizyty"
    },
    {
      "id": "AC2",
      "given": "Użytkownik przegląda dostępne terminy wizyt",
      "when": "Użytkownik filtruje lub wybiera terminy dla konkretnego specjalisty albo zakresu dat",
      "then": "System zawęża listę wyników do terminów spełniających wybrane kryteria"
    },
    {
      "id": "AC3",
      "given": "Użytkownik jest zalogowany i wybrał dostępny termin wizyty",
      "when": "Użytkownik potwierdza rezerwację terminu",
      "then": "System zapisuje rezerwację, oznacza termin jako zajęty i prezentuje potwierdzenie rezerwacji"
    },
    {
      "id": "AC4",
      "given": "Dwóch użytkowników próbuje zarezerwować ten sam dostępny termin w tym samym czasie",
      "when": "Jeden z użytkowników zakończy rezerwację jako pierwszy",
      "then": "System przydziela termin tylko pierwszej poprawnie zapisanej rezerwacji, a drugiemu użytkownikowi wyświetla informację o braku dostępności terminu"
    },
    {
      "id": "AC5",
      "given": "Użytkownik jest zalogowany i posiada aktywną własną rezerwację",
      "when": "Użytkownik anuluje tę rezerwację",
      "then": "System usuwa rezerwację, ponownie oznacza termin jako dostępny i prezentuje potwierdzenie anulowania"
    },
    {
      "id": "AC6",
      "given": "Użytkownik jest zalogowany, ale wskazana rezerwacja nie należy do niego",
      "when": "Użytkownik próbuje anulować tę rezerwację",
      "then": "System blokuje operację i wyświetla komunikat o braku uprawnień do anulowania tej rezerwacji"
    },
    {
      "id": "AC7",
      "given": "Specjalista jest zalogowany i znajduje się w widoku zarządzania grafikiem",
      "when": "Specjalista dodaje nowy wolny termin wizyty",
      "then": "System zapisuje termin w grafiku specjalisty i udostępnia go użytkownikom jako dostępny"
    },
    {
      "id": "AC8",
      "given": "Specjalista jest zalogowany i posiada istniejący termin w swoim grafiku, który nie jest zarezerwowany",
      "when": "Specjalista edytuje lub usuwa ten termin",
      "then": "System aktualizuje grafik zgodnie ze zmianą i odzwierciedla nowy stan dostępności terminu"
    },
    {
      "id": "AC9",
      "given": "Specjalista jest zalogowany i posiada zarezerwowane wizyty w systemie",
      "when": "Specjalista wyświetla listę swoich wizyt",
      "then": "System pokazuje wszystkie zarezerwowane wizyty przypisane do tego specjalisty wraz z datą, godziną i danymi rezerwacji"
    },
    {
      "id": "AC10",
      "given": "Administrator jest zalogowany i posiada uprawnienia do zarządzania rolami",
      "when": "Administrator zmienia rolę wybranego konta użytkownika",
      "then": "System zapisuje nową rolę i stosuje odpowiadające jej uprawnienia dostępu"
    },
    {
      "id": "AC11",
      "given": "Administrator jest zalogowany i znajduje się w widoku nadzoru rezerwacji",
      "when": "Administrator przegląda rezerwacje w systemie",
      "then": "System pokazuje listę wszystkich rezerwacji wraz z ich statusem, użytkownikiem, specjalistą oraz terminem wizyty"
    },
    {
      "id": "AC12",
      "given": "Administrator jest zalogowany i znajduje się w widoku zarządzania kontami",
      "when": "Administrator tworzy, edytuje, aktywuje lub dezaktywuje konto użytkownika albo specjalisty",
      "then": "System zapisuje zmiany danych konta i odzwierciedla aktualny status konta w systemie"
    }
  ]
}

