  "roles": [
    {
      "name": "Użytkownik",
      "permissions": [
        "przeglądanie dostępnych terminów",
        "dokonywanie rezerwacji",
        "anulowanie własnych rezerwacji"
      ]
    },
    {
      "name": "Specjalista",
      "permissions": [
        "zarządzanie własnym grafikiem",
        "przeglądanie listy zarezerwowanych wizyt",
        "anulowanie wizyt pacjentów"
      ]
    },
    {
      "name": "Administrator",
      "permissions": [
        "zarządzanie kontami użytkowników",
        "konfiguracja ról i uprawnień",
        "nadzór nad wszystkimi rezerwacjami"
      ]
    }
