column6:
{
  "non_functional_requirements": [
    {
      "id": "NFR1",
      "description": "System musi zapewniać czas odpowiedzi na zapytanie o dostępne terminy poniżej 2 sekund przy obciążeniu do 500 równoczesnych użytkowników."
    },
    {
      "id": "NFR2",
      "description": "Wszystkie dane osobowe użytkowników oraz szczegóły wizyt muszą być szyfrowane w spoczynku i podczas transmisji zgodnie ze standardem AES-256."
    },
    {
      "id": "NFR3",
      "description": "System musi charakteryzować się dostępnością (uptime) na poziomie 99,9% w skali miesiąca."
    },
    {
      "id": "NFR4",
      "description": "Interfejs użytkownika musi być w pełni responsywny (RWD), zapewniając poprawną obsługę na urządzeniach mobilnych i desktopowych."
    },
    {
      "id": "NFR5",
      "description": "System musi zapewniać integralność danych i izolację transakcji na poziomie 'Serializable', aby wykluczyć ryzyko podwójnej rezerwacji tego samego terminu."
    }
  ],
  "user_stories": [
    {
      "id": "US1",
      "description": "Jako Użytkownik chcę wyszukiwać specjalistów po nazwisku i specjalizacji, aby szybko znaleźć właściwą osobę."
    },
    {
      "id": "US2",
      "description": "Jako Użytkownik chcę otrzymać potwierdzenie rezerwacji na adres e-mail, aby mieć pisemny dowód umówionej wizyty."
    },
    {
      "id": "US3",
      "description": "Jako Specjalista chcę definiować reguły powtarzalności mojego grafiku, aby automatycznie generować dostępne terminy na kolejne tygodnie."
    },
    {
      "id": "US4",
      "description": "Jako Specjalista chcę mieć podgląd danych kontaktowych pacjenta przy zarezerwowanej wizycie, aby móc się z nim skontaktować w razie potrzeby."
    },
    {
      "id": "US5",
      "description": "Jako Administrator chcę mieć możliwość blokowania kont użytkowników naruszających regulamin, aby dbać o bezpieczeństwo i jakość usług w systemie."
    }
  ]
}

